import { Meter } from '@tale-ui/react/meter';

export function DiskUsageMeter() {
  return (
    <Meter.Root value={75} minValue={0} maxValue={100}>
      <Meter.Header>
        <Meter.Label>Disk Usage</Meter.Label>
        <Meter.Value />
      </Meter.Header>
      <Meter.Track>
        <Meter.Indicator value={75} />
      </Meter.Track>
    </Meter.Root>
  );
}
